import{_ as e,o as i,c as s,ak as l}from"./chunks/framework.DwHlt8HN.js";const b=JSON.parse('{"title":"索引与性能优化","description":"","frontmatter":{},"headers":[],"relativePath":"mysql/optimize/index.md","filePath":"mysql/optimize/index.md","lastUpdated":1774248380000}'),n={name:"mysql/optimize/index.md"};function t(r,a,o,d,p,h){return i(),s("div",null,[...a[0]||(a[0]=[l(`<h1 id="索引与性能优化" tabindex="-1">索引与性能优化 <a class="header-anchor" href="#索引与性能优化" aria-label="Permalink to “索引与性能优化”">​</a></h1><p>凌晨 3 点，你的监控系统报警：数据库 CPU 100%，所有接口超时。</p><p>你翻遍代码没发现问题，重启服务后好了 5 分钟，然后再次崩溃。</p><p>这不是代码的错——是你的查询没有索引，全表扫描把数据库跑死了。</p><p>MySQL 性能优化，80% 的问题都出在索引上。学会索引，就学会了 MySQL 性能优化的精髓。</p><hr><h2 id="内容地图" tabindex="-1">内容地图 <a class="header-anchor" href="#内容地图" aria-label="Permalink to “内容地图”">​</a></h2><p>本模块覆盖 MySQL 性能优化的核心知识，从索引原理到 SQL 调优，是面试和实战中最常考的领域。</p><h3 id="索引基础" tabindex="-1">索引基础 <a class="header-anchor" href="#索引基础" aria-label="Permalink to “索引基础”">​</a></h3><ul><li><a href="/database/mysql/optimize/index/basic">索引基础：什么是索引、为什么快、什么时候值得建</a></li><li><a href="/database/mysql/optimize/index/type">索引类型：聚簇索引 vs 二级索引、联合索引、B+ 树、Hash 索引</a></li><li><a href="/database/mysql/optimize/index/ops">索引操作：分类体系、创建与删除、降序索引、隐藏索引</a></li><li><a href="/database/mysql/optimize/index/scenario">索引设计：适合/不适合创建索引的场景</a></li></ul><h3 id="innodb-存储结构" tabindex="-1">InnoDB 存储结构 <a class="header-anchor" href="#innodb-存储结构" aria-label="Permalink to “InnoDB 存储结构”">​</a></h3><ul><li><a href="/database/mysql/optimize/innodb/page">页结构：数据页的 7 个组成部分、记录头信息、页目录</a></li><li><a href="/database/mysql/optimize/innodb/row-format">行格式：Compact vs Dynamic、行溢出详解</a></li><li><a href="/database/mysql/optimize/innodb/space">表空间：区、段、碎片区、表空间结构</a></li></ul><h3 id="性能分析工具" tabindex="-1">性能分析工具 <a class="header-anchor" href="#性能分析工具" aria-label="Permalink to “性能分析工具”">​</a></h3><ul><li><a href="/database/mysql/optimize/tool/slow-log">慢查询日志：配置、阈值、SHOW PROFILE</a></li><li><a href="/database/mysql/optimize/tool/explain">EXPLAIN：type/key/rows/Extra 核心字段解读</a></li><li><a href="/database/mysql/optimize/tool/trace">trace：SQL 执行的完整跟踪、Sys schema</a></li></ul><h3 id="sql-优化实战" tabindex="-1">SQL 优化实战 <a class="header-anchor" href="#sql-优化实战" aria-label="Permalink to “SQL 优化实战”">​</a></h3><ul><li><a href="/database/mysql/optimize/sql/index-invalid">索引失效的 11 种情况：最常踩的坑</a></li><li><a href="/database/mysql/optimize/sql/join-subquery">JOIN 与子查询优化：驱动表选择、排序分组优化</a></li><li><a href="/database/mysql/optimize/sql/pagination-covering">分页优化：深度分页问题、覆盖索引、ICP</a></li><li><a href="/database/mysql/optimize/sql/design">主键与表设计：自增主键、UUID、范式与反范式</a></li><li><a href="/database/mysql/optimize/overall-tuning">数据库调优：硬件配置、参数调优、大表优化</a></li></ul><hr><h2 id="学习路径" tabindex="-1">学习路径 <a class="header-anchor" href="#学习路径" aria-label="Permalink to “学习路径”">​</a></h2><div class="language- line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark" style="--shiki-light:#24292e;--shiki-dark:#e1e4e8;--shiki-light-bg:#fff;--shiki-dark-bg:#24292e;" tabindex="0" dir="ltr"><code><span class="line"><span>第一天：理解索引原理（索引类型 + InnoDB 结构）</span></span>
<span class="line"><span>第二天：掌握分析工具（慢查询日志 + EXPLAIN）</span></span>
<span class="line"><span>第三天：SQL 优化实战（索引失效 + 常见优化）</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br><span class="line-number">2</span><br><span class="line-number">3</span><br></div></div><p>建议先从 <a href="/database/mysql/optimize/index/basic">索引基础</a> 入手，理解 B+ 树为什么比全表扫描快，再学习 EXPLAIN 工具，最后才是具体的优化技巧。没有原理支撑的优化是盲目的。</p><hr><h2 id="下一步" tabindex="-1">下一步 <a class="header-anchor" href="#下一步" aria-label="Permalink to “下一步”">​</a></h2><p>索引是什么？为什么它能让查询快几十倍？</p><p>从 <a href="/database/mysql/optimize/index/basic">索引基础</a> 开始。</p>`,24)])])}const c=e(n,[["render",t]]);export{b as __pageData,c as default};
